class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> res = new ArrayList<>();
        backtrack(res, num, 0);
        return res.size() >= 3 ? res : new ArrayList<>();
    }

    private boolean backtrack(List<Integer> res, String num, int start) {
        if (start == num.length() && res.size() >= 3) return true;
        for (int i = start; i < num.length(); i++) {
            String cur = num.substring(start, i + 1);
            if (cur.length() > 1 && cur.charAt(0) == '0') break;
            long n = Long.parseLong(cur);
            if (n > Integer.MAX_VALUE) break;
            if (res.size() >= 2 && n > res.get(res.size() - 1) + res.get(res.size() - 2)) break;
            if (res.size() < 2 || n == res.get(res.size() - 1) + res.get(res.get(res.size() - 2))) {
                res.add((int) n);
                if (backtrack(res, num, i + 1)) return true;
                res.remove(res.size() - 1);
            }
        }
        return false;
    }
}
